class TrieNode:
    def __init__(self):
        self.children = [None, None] # children[0] for bit 0, children[1] for bit 1

class Trie:
    def __init__(self, L_BITS=30):
        self.root = TrieNode()
        self.L_BITS = L_BITS

    def insert(self, num):
        node = self.root
        for i in range(self.L_BITS, -1, -1):
            bit = (num >> i) & 1
            if node.children[bit] is None:
                node.children[bit] = TrieNode()
            node = node.children[bit]

    def find_max_xor(self, num):
        node = self.root
        max_xor_so_far = 0
        for i in range(self.L_BITS, -1, -1):
            bit = (num >> i) & 1
            opposite_bit = 1 - bit

            if node.children[opposite_bit] is not None:
                max_xor_so_far |= (1 << i)
                node = node.children[opposite_bit]
            else:
                node = node.children[bit]
        return max_xor_so_far

def findMaximumXOR(nums):
    if not nums or len(nums) < 2:
        return 0

    # L_BITS determines the number of bits to consider.
    # For numbers up to 2^31 - 1, we need 31 bits (from index 0 to 30).
    # So, L_BITS = 30 means iterating from bit 30 down to 0.
    L_BITS = 30 

    trie = Trie(L_BITS)

    max_xor_val = 0

    # Insert the first number into the Trie.
    trie.insert(nums[0])

    # Iterate through the rest of the numbers.
    for i in range(1, len(nums)):
        # For each number, find its maximum XOR with any number already in the Trie.
        current_num_max_xor = trie.find_max_xor(nums[i])
        max_xor_val = max(max_xor_val, current_num_max_xor)

        # Then, insert the current number into the Trie for future comparisons.
        trie.insert(nums[i])

    return max_xor_val
